from kaggle_environments import make
import json

# Initialize Kaggle multi-agent environment
env = make('connectx', configuration={'rows': 10, 'columns': 10, 'inarow': 5, 'episodeSteps': 50})

# Draft Phase: Generate deterministic 50-step plan under DCCD schema
def generate_draft_plan(model, env_state, max_constraints=7):
    plan_schema = {
        'type': 'object',
        'properties': {
            'steps': {'type': 'array', 'maxItems': 50},
            'goal_state': {'type': 'string'},
            'fallback_triggers': {'type': 'array', 'maxItems': 3}
        },
        'additionalProperties': False,
        'maxConstraints': max_constraints  # Projection Tax threshold
    }
    return model.generate_plan(env_state, schema=plan_schema)

# Guard Phase: Execute plan against adversarial environment
def execute_with_guard(plan, env, adversarial_perturbation_fn):
    executed_steps = []
    goal_state_registry = {i: plan['steps'][i] for i in range(len(plan['steps']))}
    for step in range(50):
        if step % 12 == 0:  # Goal-state reinjection every 12 steps
            env.reinject_goal_state(goal_state_registry)
        perturbed_env = adversarial_perturbation_fn(env.state)
        action = env.step(plan['steps'][step], perturbed_env)
        executed_steps.append(action)
    return executed_steps

# Executive Plan Deviation Quotient calculator
def compute_EPDQ(planned_steps, executed_steps):
    from difflib import SequenceMatcher
    planned_str = ' '.join(str(s) for s in planned_steps)
    executed_str = ' '.join(str(s) for s in executed_steps)
    similarity = SequenceMatcher(None, planned_str, executed_str).ratio()
    return 1.0 - similarity  # 0.0 = perfect adherence, 1.0 = complete deviation

