import numpy as np
from collections import defaultdict

# Hidden motive archetypes for sub-agents
AGENT_ARCHETYPES = {
    'defector': {'cooperation_probability': 0.1, 'deception_signal': 0.9},
    'cooperator': {'cooperation_probability': 0.9, 'deception_signal': 0.1},
    'opportunist': {'cooperation_probability': 0.5, 'deception_signal': 0.7}
}

# VSA Belief State Tracker (simplified vector symbolic)
class VSABeliefTracker:
    def __init__(self, n_agents=3, vector_dim=1024):
        self.belief_vectors = {a: np.random.randn(vector_dim) for a in range(n_agents)}
        self.belief_history = defaultdict(list)  # temporal trajectory
        self.update_timestamps = defaultdict(list)

    def update_belief(self, agent_id, observation, turn):
        # Bind new evidence via circular convolution (VSA operation)
        evidence_vector = np.fft.ifft(
            np.fft.fft(self.belief_vectors[agent_id]) * np.fft.fft(observation)
        ).real
        self.belief_history[agent_id].append(self.belief_vectors[agent_id].copy())
        self.belief_vectors[agent_id] = evidence_vector / np.linalg.norm(evidence_vector)
        self.update_timestamps[agent_id].append(turn)

    def get_pre_update_belief(self, agent_id, update_index):
        return self.belief_history[agent_id][update_index] if update_index < len(self.belief_history[agent_id]) else None

# Bayesian Belief Update Delta calculator
def compute_BBUD(model_inferred_beliefs, ground_truth_beliefs):
    from scipy.stats import entropy
    total_kl = 0
    for agent_id in ground_truth_beliefs:
        inferred = np.abs(model_inferred_beliefs[agent_id]) + 1e-10
        truth = np.abs(ground_truth_beliefs[agent_id]) + 1e-10
        inferred /= inferred.sum()
        truth /= truth.sum()
        total_kl += entropy(inferred, truth)
    return total_kl / len(ground_truth_beliefs)
